-- Add a reusable 300-word factory Chinese deck with pre-generated audio.
insert into public.template_decks (slug, name, description, level)
values (
  'nha-may-xuong-300',
  'Tiếng Trung nhà máy/xưởng - 300 từ',
  '300 từ vựng tiếng Trung thực tế về máy móc, dây chuyền, thao tác sản xuất, kiểm tra chất lượng, lỗi sản phẩm, bảo trì, kho vận và an toàn lao động. Mỗi từ có pinyin, nghĩa tiếng Việt, câu ví dụ theo ngữ cảnh và audio tạo sẵn.',
  'Nhà máy'
)
on conflict (slug) do update
set
  name = excluded.name,
  description = excluded.description,
  level = excluded.level;

with target_deck as (
  select id
  from public.template_decks
  where slug = 'nha-may-xuong-300'
)
insert into public.template_cards (
  template_deck_id,
  chinese,
  pinyin,
  meaning_vi,
  example_cn,
  example_pinyin,
  example_vi,
  word_audio_url,
  sentence_audio_url,
  position
)
select
  target_deck.id,
  card.chinese,
  card.pinyin,
  card.meaning_vi,
  card.example_cn,
  card.example_pinyin,
  card.example_vi,
  card.word_audio_url,
  card.sentence_audio_url,
  card.position
from target_deck
cross join (
  values
    ('工人', 'gōngrén', 'công nhân', '工人正在组装机器零件以完成生产任务。', 'Gōngrén zhèngzài zǔzhuāng jīqì língjiàn yǐ wánchéng shēngchǎn rènwu.', 'Công nhân đang lắp ráp các bộ phận máy để hoàn thành nhiệm vụ sản xuất.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/word-bff01f9cc7b66c85b8bb963f.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/sentence-e1eb3872e36220d6543a7951.mp3', 1),
