    ('检查周期', 'jiǎnchá zhōuqī', 'chu kỳ kiểm tra', '设备的检查周期应严格按照维修手册执行。', 'Shèbèi de jiǎnchá zhōuqī yīng yángé ànzhào wéixiū shǒucè zhíxíng.', 'Chu kỳ kiểm tra thiết bị phải được thực hiện nghiêm ngặt theo sổ tay bảo trì.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/word-6e7065becb0cbd38bcd072e0.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/sentence-83b0fc2d15972aac4ff990b3.mp3', 216),
    ('故障排除', 'gùzhàng páichú', 'xử lý sự cố', '技术人员迅速进行故障排除，恢复生产进度。', 'Jìshù rényuán xùnsù jìnxíng gùzhàng páichú, huīfù shēngchǎn jìndù.', 'Kỹ thuật viên nhanh chóng xử lý sự cố, phục hồi tiến độ sản xuất.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/word-6d57fce26ab711c9127d4017.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/sentence-932f226c04ed9a979e066f01.mp3', 217),
    ('润滑油更换', 'rùnhuá yóu gēnghuàn', 'thay dầu bôi trơn', '设备润滑油更换周期应严格遵守。', 'Shèbèi rùnhuá yóu gēnghuàn zhōuqī yīng yángé zūnshǒu.', 'Chu kỳ thay dầu bôi trơn thiết bị phải được tuân thủ nghiêm ngặt.', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/word-642782854955022a27cee4dd.mp3', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/nha-may-xuong-300/sentence-a10dd6575a495cbaf7a40697.mp3', 218),
